3723   case Intrinsic::vector_reduce_add:
3724   case Intrinsic::vector_reduce_mul:
3725   case Intrinsic::vector_reduce_and:
3726   case Intrinsic::vector_reduce_or:
3727   case Intrinsic::vector_reduce_xor:
3728   case Intrinsic::vector_reduce_smin:
3729   case Intrinsic::vector_reduce_smax:
3730   case Intrinsic::vector_reduce_umin:
3731   case Intrinsic::vector_reduce_umax:
