3737   // Find all the inputs when looking through operations that do not alter the
3738   // lane order (binops, for example). Currently we look for a single shuffle,
3739   // and can ignore splat values.
3740   std::queue<Value *> Worklist;
3741   SmallPtrSet<Value *, 4> Visited;
3742   ShuffleVectorInst *Shuffle = nullptr;
3743   if (auto *Op = dyn_cast<Instruction>(I.getOperand(0)))
3744     Worklist.push(Op);
