3282 static InstLane lookThroughShuffles(Use *U, int Lane) {
3283   while (auto *SV = dyn_cast<ShuffleVectorInst>(U->get())) {
3284     unsigned NumElts =
3285         cast<FixedVectorType>(SV->getOperand(0)->getType())->getNumElements();
3286     int M = SV->getMaskValue(Lane);
3287     if (M < 0)
3288       return {nullptr, PoisonMaskElem};
3289     if (static_cast<unsigned>(M) < NumElts) {
3290       U = &SV->getOperandUse(0);
3291       Lane = M;
3292     } else {
3293       U = &SV->getOperandUse(1);
3294       Lane = M - NumElts;
3295     }
3296   }
3297   return InstLane{U, Lane};
3298 }
