3314 /// Detect concat of multiple values into a vector
3315 static bool isFreeConcat(ArrayRef<InstLane> Item, TTI::TargetCostKind CostKind,
3316                          const TargetTransformInfo &TTI) {
3317   auto *Ty = cast<FixedVectorType>(Item.front().first->get()->getType());
3318   unsigned NumElts = Ty->getNumElements();
3319   if (Item.size() == NumElts || NumElts == 1 || Item.size() % NumElts != 0)
3320     return false;
3321 
3322   // Check that the concat is free, usually meaning that the type will be split
3323   // during legalization.
3324   SmallVector<int, 16> ConcatMask(NumElts * 2);
3325   std::iota(ConcatMask.begin(), ConcatMask.end(), 0);
3326   if (TTI.getShuffleCost(TTI::SK_PermuteTwoSrc,
3327                          FixedVectorType::get(Ty->getScalarType(), NumElts * 2),
3328                          Ty, ConcatMask, CostKind) != 0)
3329     return false;
3330 
3331   unsigned NumSlices = Item.size() / NumElts;
3332   // Currently we generate a tree of shuffles for the concats, which limits us
3333   // to a power2.
3334   if (!isPowerOf2_32(NumSlices))
3335     return false;
3336   for (unsigned Slice = 0; Slice < NumSlices; ++Slice) {
3337     Use *SliceV = Item[Slice * NumElts].first;
3338     if (!SliceV || SliceV->get()->getType() != Ty)
3339       return false;
3340     for (unsigned Elt = 0; Elt < NumElts; ++Elt) {
3341       auto [V, Lane] = Item[Slice * NumElts + Elt];
3342       if (Lane != static_cast<int>(Elt) || SliceV->get() != V->get())
3343         return false;
3344     }
3345   }
3346   return true;
3347 }
