3349 static Value *generateNewInstTree(ArrayRef<InstLane> Item, FixedVectorType *Ty,
3350                                   const SmallPtrSet<Use *, 4> &IdentityLeafs,
3351                                   const SmallPtrSet<Use *, 4> &SplatLeafs,
3352                                   const SmallPtrSet<Use *, 4> &ConcatLeafs,
3353                                   IRBuilderBase &Builder,
3354                                   const TargetTransformInfo *TTI) {
3355   auto [FrontU, FrontLane] = Item.front();
3356 
3357   if (IdentityLeafs.contains(FrontU)) {
3358     return FrontU->get();
3359   }
3360   if (SplatLeafs.contains(FrontU)) {
3361     SmallVector<int, 16> Mask(Ty->getNumElements(), FrontLane);
3362     return Builder.CreateShuffleVector(FrontU->get(), Mask);
3363   }
3364   if (ConcatLeafs.contains(FrontU)) {
3365     unsigned NumElts =
3366         cast<FixedVectorType>(FrontU->get()->getType())->getNumElements();
3367     SmallVector<Value *> Values(Item.size() / NumElts, nullptr);
3368     for (unsigned S = 0; S < Values.size(); ++S)
3369       Values[S] = Item[S * NumElts].first->get();
3370 
3371     while (Values.size() > 1) {
3372       NumElts *= 2;
3373       SmallVector<int, 16> Mask(NumElts, 0);
3374       std::iota(Mask.begin(), Mask.end(), 0);
3375       SmallVector<Value *> NewValues(Values.size() / 2, nullptr);
3376       for (unsigned S = 0; S < NewValues.size(); ++S)
3377         NewValues[S] =
3378             Builder.CreateShuffleVector(Values[S * 2], Values[S * 2 + 1], Mask);
3379       Values = NewValues;
3380     }
3381     return Values[0];
3382   }
3383 
3384   auto *I = cast<Instruction>(FrontU->get());
3385   auto *II = dyn_cast<IntrinsicInst>(I);
3386   unsigned NumOps = I->getNumOperands() - (II ? 1 : 0);
3387   SmallVector<Value *> Ops(NumOps);
3388   for (unsigned Idx = 0; Idx < NumOps; Idx++) {
3389     if (II &&
3390         isVectorIntrinsicWithScalarOpAtArg(II->getIntrinsicID(), Idx, TTI)) {
3391       Ops[Idx] = II->getOperand(Idx);
3392       continue;
3393     }
3394     Ops[Idx] = generateNewInstTree(generateInstLaneVectorFromOperand(Item, Idx),
3395                                    Ty, IdentityLeafs, SplatLeafs, ConcatLeafs,
3396                                    Builder, TTI);
3397   }
3398 
3399   SmallVector<Value *, 8> ValueList;
3400   for (const auto &Lane : Item)
3401     if (Lane.first)
3402       ValueList.push_back(Lane.first->get());
3403 
3404   Type *DstTy =
3405       FixedVectorType::get(I->getType()->getScalarType(), Ty->getNumElements());
3406   if (auto *BI = dyn_cast<BinaryOperator>(I)) {
3407     auto *Value = Builder.CreateBinOp((Instruction::BinaryOps)BI->getOpcode(),
3408                                       Ops[0], Ops[1]);
3409     propagateIRFlags(Value, ValueList);
3410     return Value;
3411   }
3412   if (auto *CI = dyn_cast<CmpInst>(I)) {
3413     auto *Value = Builder.CreateCmp(CI->getPredicate(), Ops[0], Ops[1]);
3414     propagateIRFlags(Value, ValueList);
3415     return Value;
3416   }
3417   if (auto *SI = dyn_cast<SelectInst>(I)) {
3418     auto *Value = Builder.CreateSelect(Ops[0], Ops[1], Ops[2], "", SI);
3419     propagateIRFlags(Value, ValueList);
3420     return Value;
3421   }
3422   if (auto *CI = dyn_cast<CastInst>(I)) {
3423     auto *Value = Builder.CreateCast(CI->getOpcode(), Ops[0], DstTy);
3424     propagateIRFlags(Value, ValueList);
3425     return Value;
3426   }
3427   if (II) {
3428     auto *Value = Builder.CreateIntrinsic(DstTy, II->getIntrinsicID(), Ops);
3429     propagateIRFlags(Value, ValueList);
3430     return Value;
3431   }
3432   assert(isa<UnaryInstruction>(I) && "Unexpected instruction type in Generate");
3433   auto *Value =
3434       Builder.CreateUnOp((Instruction::UnaryOps)I->getOpcode(), Ops[0]);
3435   propagateIRFlags(Value, ValueList);
3436   return Value;
3437 }
