1716   void freeze(IRBuilderBase &Builder, Instruction &UserI) {
1717     assert(isSafeWithFreeze() &&
1718            "should only be used when freezing is required");
1719     assert(is_contained(ToFreeze->users(), &UserI) &&
1720            "UserI must be a user of ToFreeze");
1721     IRBuilder<>::InsertPointGuard Guard(Builder);
1722     Builder.SetInsertPoint(cast<Instruction>(&UserI));
1723     Value *Frozen =
1724         Builder.CreateFreeze(ToFreeze, ToFreeze->getName() + ".frozen");
1725     for (Use &U : make_early_inc_range((UserI.operands())))
1726       if (U.get() == ToFreeze)
1727         U.set(Frozen);
1728 
1729     ToFreeze = nullptr;
1730   }
