1734 /// Check if it is legal to scalarize a memory access to \p VecTy at index \p
1735 /// Idx. \p Idx must access a valid vector element.
1736 static ScalarizationResult canScalarizeAccess(VectorType *VecTy, Value *Idx,
1737                                               Instruction *CtxI,
1738                                               AssumptionCache &AC,
1739                                               const DominatorTree &DT) {
1740   // We do checks for both fixed vector types and scalable vector types.
1741   // This is the number of elements of fixed vector types,
1742   // or the minimum number of elements of scalable vector types.
1743   uint64_t NumElements = VecTy->getElementCount().getKnownMinValue();
1744   unsigned IntWidth = Idx->getType()->getScalarSizeInBits();
1745 
1746   if (auto *C = dyn_cast<ConstantInt>(Idx)) {
1747     if (C->getValue().ult(NumElements))
1748       return ScalarizationResult::safe();
1749     return ScalarizationResult::unsafe();
1750   }
1751 
1752   // Always unsafe if the index type can't handle all inbound values.
1753   if (!llvm::isUIntN(IntWidth, NumElements))
1754     return ScalarizationResult::unsafe();
1755 
1756   APInt Zero(IntWidth, 0);
1757   APInt MaxElts(IntWidth, NumElements);
1758   ConstantRange ValidIndices(Zero, MaxElts);
1759   ConstantRange IdxRange(IntWidth, true);
1760 
1761   if (isGuaranteedNotToBePoison(Idx, &AC)) {
1762     if (ValidIndices.contains(computeConstantRange(Idx, /* ForSigned */ false,
1763                                                    true, &AC, CtxI, &DT)))
1764       return ScalarizationResult::safe();
1765     return ScalarizationResult::unsafe();
1766   }
1767 
1768   // If the index may be poison, check if we can insert a freeze before the
1769   // range of the index is restricted.
1770   Value *IdxBase;
1771   ConstantInt *CI;
1772   if (match(Idx, m_And(m_Value(IdxBase), m_ConstantInt(CI)))) {
1773     IdxRange = IdxRange.binaryAnd(CI->getValue());
1774   } else if (match(Idx, m_URem(m_Value(IdxBase), m_ConstantInt(CI)))) {
1775     IdxRange = IdxRange.urem(CI->getValue());
1776   }
1777 
1778   if (ValidIndices.contains(IdxRange))
1779     return ScalarizationResult::safeWithFreeze(IdxBase);
1780   return ScalarizationResult::unsafe();
1781 }
