1783 /// The memory operation on a vector of \p ScalarType had alignment of
1784 /// \p VectorAlignment. Compute the maximal, but conservatively correct,
1785 /// alignment that will be valid for the memory operation on a single scalar
1786 /// element of the same type with index \p Idx.
1787 static Align computeAlignmentAfterScalarization(Align VectorAlignment,
1788                                                 Type *ScalarType, Value *Idx,
1789                                                 const DataLayout &DL) {
1790   if (auto *C = dyn_cast<ConstantInt>(Idx))
1791     return commonAlignment(VectorAlignment,
1792                            C->getZExtValue() * DL.getTypeStoreSize(ScalarType));
1793   return commonAlignment(VectorAlignment, DL.getTypeStoreSize(ScalarType));
1794 }
