1796 // Combine patterns like:
1797 //   %0 = load <4 x i32>, <4 x i32>* %a
1798 //   %1 = insertelement <4 x i32> %0, i32 %b, i32 1
1799 //   store <4 x i32> %1, <4 x i32>* %a
1800 // to:
1801 //   %0 = bitcast <4 x i32>* %a to i32*
1802 //   %1 = getelementptr inbounds i32, i32* %0, i64 0, i64 1
1803 //   store i32 %b, i32* %1
1804 bool VectorCombine::foldSingleElementStore(Instruction &I) {
1805   if (!TTI.allowVectorElementIndexingUsingGEP())
1806     return false;
1807   auto *SI = cast<StoreInst>(&I);
1808   if (!SI->isSimple() || !isa<VectorType>(SI->getValueOperand()->getType()))
1809     return false;
1810 
1811   // TODO: Combine more complicated patterns (multiple insert) by referencing
1812   // TargetTransformInfo.
1813   Instruction *Source;
1814   Value *NewElement;
1815   Value *Idx;
1816   if (!match(SI->getValueOperand(),
1817              m_InsertElt(m_Instruction(Source), m_Value(NewElement),
1818                          m_Value(Idx))))
1819     return false;
1820 
1821   if (auto *Load = dyn_cast<LoadInst>(Source)) {
1822     auto VecTy = cast<VectorType>(SI->getValueOperand()->getType());
1823     Value *SrcAddr = Load->getPointerOperand()->stripPointerCasts();
1824     // Don't optimize for atomic/volatile load or store. Ensure memory is not
1825     // modified between, vector type matches store size, and index is inbounds.
1826     if (!Load->isSimple() || Load->getParent() != SI->getParent() ||
1827         !DL->typeSizeEqualsStoreSize(Load->getType()->getScalarType()) ||
1828         SrcAddr != SI->getPointerOperand()->stripPointerCasts())
1829       return false;
1830 
1831     auto ScalarizableIdx = canScalarizeAccess(VecTy, Idx, Load, AC, DT);
1832     if (ScalarizableIdx.isUnsafe() ||
1833         isMemModifiedBetween(Load->getIterator(), SI->getIterator(),
1834                              MemoryLocation::get(SI), AA))
1835       return false;
1836 
1837     // Ensure we add the load back to the worklist BEFORE its users so they can
1838     // erased in the correct order.
1839     Worklist.push(Load);
1840 
1841     if (ScalarizableIdx.isSafeWithFreeze())
1842       ScalarizableIdx.freeze(Builder, *cast<Instruction>(Idx));
1843     Value *GEP = Builder.CreateInBoundsGEP(
1844         SI->getValueOperand()->getType(), SI->getPointerOperand(),
1845         {ConstantInt::get(Idx->getType(), 0), Idx});
1846     StoreInst *NSI = Builder.CreateStore(NewElement, GEP);
1847     NSI->copyMetadata(*SI);
1848     Align ScalarOpAlignment = computeAlignmentAfterScalarization(
1849         std::max(SI->getAlign(), Load->getAlign()), NewElement->getType(), Idx,
1850         *DL);
1851     NSI->setAlignment(ScalarOpAlignment);
1852     replaceValue(I, *NSI);
1853     eraseInstruction(I);
1854     return true;
1855   }
1856 
1857   return false;
1858 }
