1860 /// Try to scalarize vector loads feeding extractelement or bitcast
1861 /// instructions.
1862 bool VectorCombine::scalarizeLoad(Instruction &I) {
1863   Value *Ptr;
1864   if (!match(&I, m_Load(m_Value(Ptr))))
1865     return false;
1866 
1867   auto *LI = cast<LoadInst>(&I);
1868   auto *VecTy = cast<VectorType>(LI->getType());
1869   if (LI->isVolatile() || !DL->typeSizeEqualsStoreSize(VecTy->getScalarType()))
1870     return false;
1871 
1872   bool AllExtracts = true;
1873   bool AllBitcasts = true;
1874   Instruction *LastCheckedInst = LI;
1875   unsigned NumInstChecked = 0;
1876 
1877   // Check what type of users we have (must either all be extracts or
1878   // bitcasts) and ensure no memory modifications between the load and
1879   // its users.
1880   for (User *U : LI->users()) {
1881     auto *UI = dyn_cast<Instruction>(U);
1882     if (!UI || UI->getParent() != LI->getParent())
1883       return false;
1884 
1885     // If any user is waiting to be erased, then bail out as this will
1886     // distort the cost calculation and possibly lead to infinite loops.
1887     if (UI->use_empty())
1888       return false;
1889 
1890     if (!isa<ExtractElementInst>(UI))
1891       AllExtracts = false;
1892     if (!isa<BitCastInst>(UI))
1893       AllBitcasts = false;
1894 
1895     // Check if any instruction between the load and the user may modify memory.
1896     if (LastCheckedInst->comesBefore(UI)) {
1897       for (Instruction &I :
1898            make_range(std::next(LI->getIterator()), UI->getIterator())) {
1899         // Bail out if we reached the check limit or the instruction may write
1900         // to memory.
1901         if (NumInstChecked == MaxInstrsToScan || I.mayWriteToMemory())
1902           return false;
1903         NumInstChecked++;
1904       }
1905       LastCheckedInst = UI;
1906     }
1907   }
1908 
1909   if (AllExtracts)
1910     return scalarizeLoadExtract(LI, VecTy, Ptr);
1911   if (AllBitcasts)
1912     return scalarizeLoadBitcast(LI, VecTy, Ptr);
1913   return false;
1914 }
