491 bool Instruction::hasNonDebugLocLoopMetadata() const {
492   // If there is no loop metadata at all, we also don't have
493   // non-debug loop metadata, obviously.
494   if (!hasMetadata(LLVMContext::MD_loop))
495     return false;
496 
497   // If we do have loop metadata, retrieve it.
498   MDNode *LoopMD = getMetadata(LLVMContext::MD_loop);
499 
500   // Check if the existing operands are debug locations. This loop
501   // should terminate after at most three iterations. Skip
502   // the first item because it is a self-reference.
503   for (const MDOperand &Op : llvm::drop_begin(LoopMD->operands())) {
504     // check for debug location type by attempting a cast.
505     if (!isa<DILocation>(Op)) {
506       return true;
507     }
508   }
509 
510   // If we get here, then all we have is debug locations in the loop metadata.
511   return false;
512 }
